<?php namespace App\Repositories\Library;use App\Repositories\BaseRepository;use App\Models\Library\BookIssue;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class BookIssueRepository extends BaseRepository{    public function __construct(BookIssue $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByBook(int $bookId): Collection    {        return $this->findByField('book_id', $bookId);    }    public function findByMember(int $memberId): Collection    {        return $this->findByField('member_id', $memberId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getIssuedBooks(): Collection    {        return $this->query()->where('status', 'issued')->get();    }    public function getOverdueBooks(): Collection    {        return $this->query()->where('due_date', '<', now())->where('status', 'issued')->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('issue_date', [$startDate, $endDate])->get();    }    public function getByDueDate(string $date): Collection    {        return $this->query()->whereDate('due_date', $date)->get();    }    public function issueBook(int $bookId, int $memberId, int $days = 14): BookIssue    {        return $this->create([            'book_id' => $bookId,            'member_id' => $memberId,            'issue_date' => now(),            'due_date' => now()->addDays($days),            'status' => 'issued',        ]);    }    public function returnBook(int $issueId): bool    {        return $this->update($issueId, [            'return_date' => now(),            'status' => 'returned',        ]);    }    public function renewBook(int $issueId, int $extraDays = 7): bool    {        $issue = $this->getById($issueId);        return $this->update($issueId, [            'due_date' => $issue->due_date->addDays($extraDays),            'renewal_count' => ($issue->renewal_count ?? 0) + 1,        ]);    }    public function getMemberIssues(int $memberId): Collection    {        return $this->query()->where('member_id', $memberId)->where('status', 'issued')->get();    }    public function countActiveIssues(): int    {        return $this->query()->where('status', 'issued')->count();    }}